import { ExternalTokenizer } from '@lezer/lr';

import { characterCodes, durationUnitChars } from '../character-codes.js';
import { Duration, Number as NumberToken } from '../parser.terms.js';

const { EOF, DASH, SPACE, DOT, COMMA, CLOSING_BRACKET } = characterCodes;

function isNumber(charCode: number): boolean {
  // Numpad key codes are already handled by codemirror.
  return charCode >= 48 && charCode <= 57;
}

/** @internal */
export const valueTokenizer = new ExternalTokenizer((inputStream) => {
  const currCharCode = inputStream.peek(0);

  // Character is not a number and not '-' -> definitely not a number / duration.
  if (!isNumber(currCharCode) && currCharCode !== DASH) {
    return;
  }

  // Array of digits and separators (.|,) so we can check if the potential
  // number actually is a number with the regex at the end.
  // We already checked the character at the current position, so we can already
  // add a digit here ('-' doesn't make a difference for the regex).
  const potentialNumberChars = ['d'];

  let peekPosition = 1;
  let peekCharCode = inputStream.peek(peekPosition);
  let peekChar = String.fromCharCode(peekCharCode);

  let potentialDuration = String.fromCharCode(currCharCode);
  let isPotentialDuration = true;
  let isPotentialNumber = true;

  // As long as the character is either a digit, '.', or ',', we keep pushing
  // the characters to the array.
  while (
    isNumber(peekCharCode) ||
    peekCharCode === DOT ||
    durationUnitChars.includes(peekChar)
  ) {
    // With the current character being a number, the token could be either a Duration or Number.
    if (isNumber(peekCharCode)) {
      potentialNumberChars.push('d');
      potentialDuration += peekChar;
    } else if (durationUnitChars.includes(peekChar)) {
      // With the current character being included in the duration units,
      // the only valid token may be a duration. Number can already be ruled out.
      isPotentialNumber = false;
      if (peekCharCode !== COMMA) {
        potentialDuration += peekChar;
      } else {
        break;
      }
    } else if (peekCharCode === DOT) {
      // With the current character being a '.', the only valid token may
      // be a number. Duration can already be ruled out.
      isPotentialDuration = false;

      potentialNumberChars.push(peekCharCode === DOT ? '.' : ',');
    } else {
      // This should never happen.
      // eslint-disable-next-line no-console
      console.log('Invalid peek character in value tokenizer.');
    }

    peekPosition += 1;
    peekCharCode = inputStream.peek(peekPosition);
    peekChar = String.fromCharCode(peekCharCode);
  }

  // Only if the character right after the potential token is either the end of
  // the input, a space or a closing bracket, the value may be a Number or Duration.
  // If not, we just return.
  const charAfterPotentialToken = inputStream.peek(peekPosition);
  if (
    peekPosition === 0 ||
    !(
      charAfterPotentialToken === EOF ||
      charAfterPotentialToken === SPACE ||
      charAfterPotentialToken === CLOSING_BRACKET ||
      charAfterPotentialToken === COMMA
    )
  ) {
    return;
  }

  // Duration should have a higher precedence than a number -> check for possibly
  if (isPotentialDuration) {
    // check if it matches the regex (one or more digits followed by one of the accepted units)
    const durationMatch = (/^\d+(ns|ms|s|m|h|d)$/.exec(potentialDuration) ||
      [])[0];

    if (durationMatch?.length === peekPosition) {
      inputStream.acceptToken(Duration, peekPosition);
    }
  }

  // If it's not a duration and also not a number, just return and let the grammar take over again.
  if (!isPotentialNumber) {
    return;
  }

  // Simple regex magic to check if the input is a valid number or not.
  // The regex matches everything with an arbitrary number of digits at the start (at least 1)
  // followed by optional decimal separator ('.') and 1 to n decimals.
  // https://regex101.com/r/rfsfrv/2

  const potentialNumber = potentialNumberChars.join('');
  const numberMatch = (/^(d+((\.?)d+)?)$/.exec(potentialNumber) || [])[0];

  if (numberMatch?.length !== peekPosition) {
    return;
  }

  inputStream.acceptToken(NumberToken, peekPosition);
});
